const item = $input.item;
const json = item.json || {};
const binary = item.binary || {};
if (!binary.data) {
  throw new Error('Downloaded media is missing binary data');
}

function extFromMime(mime, postType) {
  const m = String(mime || '').toLowerCase();
  if (m.includes('video/mp4')) return 'mp4';
  if (m.includes('image/png')) return 'png';
  if (m.includes('image/webp')) return 'webp';
  if (m.includes('image/jpeg') || m.includes('image/jpg')) return 'jpg';
  return postType === 'video' ? 'mp4' : 'jpg';
}

function mimeFromExt(ext, postType) {
  const e = String(ext || '').toLowerCase();
  if (e === 'mp4') return 'video/mp4';
  if (e === 'png') return 'image/png';
  if (e === 'webp') return 'image/webp';
  if (e === 'jpg' || e === 'jpeg') return 'image/jpeg';
  return postType === 'video' ? 'video/mp4' : 'image/jpeg';
}

const mediaRef = String(json.mediaUrl || json.mediaFileName || '');
let fileName = String(binary.data.fileName || json.mediaFileName || '').trim();
let mimeType = String(binary.data.mimeType || json.mediaFileMimeType || '').trim().toLowerCase();

let ext = '';
const refMatch = mediaRef.split('?')[0].match(/\.([a-z0-9]+)$/i);
if (refMatch) {
  ext = refMatch[1].toLowerCase();
}

if (!ext && fileName.match(/\.([a-z0-9]+)$/i)) {
  ext = fileName.match(/\.([a-z0-9]+)$/i)[1].toLowerCase();
}

if (!ext) {
  ext = extFromMime(mimeType, json.postType);
}

if (!fileName || !/\.[a-z0-9]+$/i.test(fileName)) {
  fileName = 'upload-' + String((json.mediaIndex ?? 0) + 1) + '.' + ext;
}

if (!mimeType || mimeType === 'application/octet-stream') {
  mimeType = mimeFromExt(ext, json.postType);
}

binary.data.fileName = fileName;
binary.data.fileExtension = ext;
binary.data.mimeType = mimeType;

return { json, binary };

const base=$('Expand Media Upload Items').first().json;
const uploadedMediaUrls=$input.all()
  .map(item => item.json || {})
  .map(item => item.url || item.body?.url || '')
  .filter(Boolean);
if (!uploadedMediaUrls.length) {
  throw new Error('No uploaded media URLs were returned from POST.devad.io /upload');
}
return [{json:{...base,uploadedMediaUrls}}];

